     1→import { useState, useEffect, useCallback } from "react";
     2→import { format, startOfMonth } from "date-fns";
     3→import { Calendar as CalendarIconLucide, ClipboardList as ClipboardList, Users as Users, AlertTriangle as AlertTriangle } from "lucide-react";
     4→import { Input } from "@/components/ui/input";
     5→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     6→import { ChartContainer, ChartTooltip, ChartTooltipContent } from "@/components/ui/chart";
     7→import { PieChart, Pie, Cell } from "recharts";
     8→import { LoadingSpinner } from "@/components/ui/loading-spinner";
     9→import { getSalonNavItems } from "@/config/navigation";
    10→import { useAuth } from "@/contexts/AuthContext";
    11→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    12→import { dashboardService, type DashboardStats } from "@/services/dashboardService";
    13→import { analytics } from "@/lib/analytics";
    14→
    15→const defaultChartConfig = {
    16→  value: {
    17→    label: "Agendamentos",
    18→  },
    19→};
    20→
    21→export default function DashboardPage() {
    22→  const { user } = useAuth();
    23→  const { selectedSalon } = useSelectedSalon();
    24→
    25→  const today = new Date();
    26→  const tomorrow = new Date();
    27→  tomorrow.setDate(today.getDate() + 1);
    28→
    29→  const [dateFrom, setDateFrom] = useState(format(startOfMonth(new Date()), "yyyy-MM-dd"));
    30→  const [dateTo, setDateTo] = useState(format(tomorrow, "yyyy-MM-dd"));
    31→
    32→  const [dashboardData, setDashboardData] = useState<DashboardStats | null>(null);
    33→  const [loading, setLoading] = useState(true);
    34→  const [error, setError] = useState<string | null>(null);
    35→
    36→  const navItems = getSalonNavItems(user?.role || "Profissional");
    37→
    38→  useEffect(() => {
    39→    analytics.trackEvent("dashboard_viewed", {});
    40→  }, []);
    41→
    42→  const fetchDashboardData = useCallback(async () => {
    43→    try {
    44→      setLoading(true);
    45→      setError(null);
    46→
    47→      const data = await dashboardService.getStats({
    48→        startDate: dateFrom,
    49→        endDate: dateTo,
    50→      });
    51→
    52→      setDashboardData(data);
    53→    } catch {
    54→      setError("Erro ao carregar dados do dashboard");
    55→    } finally {
    56→      setLoading(false);
    57→    }
    58→  }, [selectedSalon, dateFrom, dateTo]);
    59→
    60→  useEffect(() => {
    61→    if (selectedSalon?.id) {
    62→      fetchDashboardData();
    63→    }
    64→  }, [dateFrom, dateTo, selectedSalon?.id]);
    65→
    66→  const chartConfig =
    67→    dashboardData?.topServices.reduce(
    68→      (acc, service) => {
    69→        acc[service.name] = {
    70→          label: service.name,
    71→          color: service.color,
    72→        };
    73→        return acc;
    74→      },
    75→      { ...defaultChartConfig }
    76→    ) || defaultChartConfig;
    77→
    78→  return (
    79→    <EasySalonLayout
    80→      sideNavTitle="Easy Salon"
    81→      sideNavSubtitle="Easy Salon"
    82→      sideNavItems={navItems}
    83→    >
    84→      {/* Header row: title + date filters */}
    85→      <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4 mb-6">
    86→        <h1 className="text-xl md:text-2xl font-semibold text-foreground">Dashboard</h1>
    87→
    88→        <div className="flex items-center gap-2 min-w-0 w-full md:w-auto">
    89→          <div className="relative min-w-0 flex-1 md:flex-none">
    90→            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-muted-foreground pointer-events-none select-none">
    91→              De:
    92→            </span>
    93→            <Input
    94→              type="date"
    95→              value={dateFrom}
    96→              onChange={(e) => setDateFrom(e.target.value)}
    97→              className="pl-9 w-full md:w-auto"
    98→            />
    99→          </div>
   100→          <div className="relative min-w-0 flex-1 md:flex-none">
   101→            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-xs text-muted-foreground pointer-events-none select-none">
   102→              Até:
   103→            </span>
   104→            <Input
   105→              type="date"
   106→              value={dateTo}
   107→              onChange={(e) => setDateTo(e.target.value)}
   108→              className="pl-10 w-full md:w-auto"
   109→            />
   110→          </div>
   111→        </div>
   112→      </div>
   113→
   114→      <div className="space-y-6">
   115→        {/* No salon selected */}
   116→        {!selectedSalon && !loading && (
   117→          <div className="bg-card border border-border rounded-3xl p-6 flex flex-col items-center justify-center py-8">
   118→            <AlertTriangle className="h-12 w-12 text-yellow-500 mb-4" />
   119→            <h3 className="text-lg font-medium mb-2">Nenhum salão selecionado</h3>
   120→            <p className="text-muted-foreground text-center mb-4">
   121→              Para visualizar os dados do dashboard, você precisa selecionar um salão.
   122→            </p>
   123→          </div>
   124→        )}
   125→
   126→        {/* Loading state */}
   127→        {loading && (
   128→          <div className="flex justify-center items-center py-16">
   129→            <LoadingSpinner size="md" text="Carregando dados..." />
   130→          </div>
   131→        )}
   132→
   133→        {/* Error state */}
   134→        {error && (
   135→          <div className="bg-red-50 border border-red-200 rounded-3xl p-4 flex items-center justify-between">
   136→            <span className="text-red-800">{error}</span>
   137→            <button
   138→              onClick={fetchDashboardData}
   139→              className="ml-4 text-sm text-red-700 underline hover:text-red-900"
   140→            >
   141→              Tentar novamente
   142→            </button>
   143→          </div>
   144→        )}
   145→
   146→        {!loading && !error && dashboardData && selectedSalon && (
   147→          <>
   148→            {/* KPI Cards */}
   149→            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
   150→              <div className="bg-card border border-border p-4 rounded-3xl">
   151→                <div className="flex items-start justify-between">
   152→                  <div>
   153→                    <p className="text-sm text-muted-foreground">Agendamentos no Período</p>
   154→                    <p className="text-3xl font-bold text-foreground mt-1">
   155→                      {dashboardData.appointments.total}
   156→                    </p>
   157→                    <p className="text-xs text-muted-foreground mt-1">
   158→                      {dashboardData.appointments.thisWeek} esta semana
   159→                    </p>
   160→                  </div>
   161→                  <CalendarIconLucide className="w-5 h-5 text-muted-foreground" />
   162→                </div>
   163→              </div>
   164→
   165→              <div className="bg-card border border-border p-4 rounded-3xl">
   166→                <div className="flex items-start justify-between">
   167→                  <div>
   168→                    <p className="text-sm text-muted-foreground">Solicitações Totais</p>
   169→                    <p className="text-3xl font-bold text-foreground mt-1">
   170→                      {dashboardData.requests.total}
   171→                    </p>
   172→                    <p className="text-xs text-muted-foreground mt-1">
   173→                      {dashboardData.requests.pending} pendentes
   174→                    </p>
   175→                  </div>
   176→                  <ClipboardList className="w-5 h-5 text-muted-foreground" />
   177→                </div>
   178→              </div>
   179→
   180→              <div className="bg-card border border-border p-4 rounded-3xl">
   181→                <div className="flex items-start justify-between">
   182→                  <div>
   183→                    <p className="text-sm text-muted-foreground">Total de Clientes</p>
   184→                    <p className="text-3xl font-bold text-foreground mt-1">
   185→                      {dashboardData.clients.total}
   186→                    </p>
   187→                    <p className="text-xs text-muted-foreground mt-1">
   188→                      {dashboardData.clients.new} novos este mês
   189→                    </p>
   190→                  </div>
   191→                  <Users className="w-5 h-5 text-muted-foreground" />
   192→                </div>
   193→              </div>
   194→            </div>
   195→
   196→            {/* Services Chart */}
   197→            <div className="bg-card border border-border p-4 md:p-6 rounded-3xl">
   198→              <div className="mb-4">
   199→                <h3 className="text-lg font-semibold text-foreground">
   200→                  Serviços Mais Agendados
   201→                </h3>
   202→                <p className="text-sm text-muted-foreground">
   203→                  Distribuição dos agendamentos por tipo de serviço no período selecionado
   204→                </p>
   205→              </div>
   206→
   207→              {dashboardData.topServices.length > 0 ? (
   208→                <>
   209→                  <ChartContainer
   210→                    config={chartConfig}
   211→                    className="mx-auto aspect-square max-h-[350px]"
   212→                  >
   213→                    <PieChart>
   214→                      <ChartTooltip
   215→                        cursor={false}
   216→                        content={<ChartTooltipContent hideLabel />}
   217→                      />
   218→                      <Pie
   219→                        data={dashboardData.topServices}
   220→                        dataKey="value"
   221→                        nameKey="name"
   222→                        cx="50%"
   223→                        cy="50%"
   224→                        outerRadius={120}
   225→                        innerRadius={60}
   226→                        strokeWidth={2}
   227→                      >
   228→                        {dashboardData.topServices.map((entry, index) => (
   229→                          <Cell key={`cell-${index}`} fill={entry.color} />
   230→                        ))}
   231→                      </Pie>
   232→                    </PieChart>
   233→                  </ChartContainer>
   234→
   235→                  <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2 mt-6">
   236→                    {dashboardData.topServices.map((item, index) => (
   237→                      <div key={index} className="flex items-center gap-2">
   238→                        <div
   239→                          className="w-3 h-3 rounded-full"
   240→                          style={{ backgroundColor: item.color }}
   241→                        />
   242→                        <span className="text-sm text-muted-foreground truncate">
   243→                          {item.name}: {item.value} agendamentos
   244→                        </span>
   245→                      </div>
   246→                    ))}
   247→                  </div>
   248→                </>
   249→              ) : (
   250→                <div className="h-[250px] flex items-center justify-center">
   251→                  <p className="text-muted-foreground">
   252→                    Nenhum agendamento encontrado para o período selecionado
   253→                  </p>
   254→                </div>
   255→              )}
   256→            </div>
   257→          </>
   258→        )}
   259→      </div>
   260→    </EasySalonLayout>
   261→  );
   262→}
