     1→import React, { useState } from "react";
     2→import {
     3→  ColumnDef,
     4→  flexRender,
     5→  getCoreRowModel,
     6→  getPaginationRowModel,
     7→  useReactTable,
     8→} from "@tanstack/react-table";
     9→import {
    10→  Table,
    11→  TableBody,
    12→  TableCell,
    13→  TableHead,
    14→  TableHeader,
    15→  TableRow,
    16→} from "@/components/ui/table";
    17→import { Button } from "@/components/ui/button";
    18→import { ResponsivePagination } from "@/components/ui/responsive-pagination";
    19→import { cn } from "@/lib/utils";
    20→
    21→export interface Column<T> {
    22→  key: keyof T | string;
    23→  header: React.ReactNode | string;
    24→  render?: (value: any, row: T) => React.ReactNode;
    25→  className?: string;
    26→  width?: string;
    27→}
    28→
    29→export interface TableAction<T> {
    30→  label: string;
    31→  icon: React.ReactNode;
    32→  onClick: (row: T, event: React.MouseEvent) => void;
    33→  variant?: "default" | "destructive" | "outline" | "ghost";
    34→  disabled?: (row: T) => boolean;
    35→  hidden?: (row: T) => boolean;
    36→}
    37→
    38→interface MobileCardConfig<T> {
    39→  title: keyof T | ((row: T) => React.ReactNode);
    40→  subtitle?: keyof T | ((row: T) => React.ReactNode);
    41→  badge?: keyof T | ((row: T) => React.ReactNode);
    42→  excludeFromGrid?: (keyof T)[];
    43→}
    44→
    45→interface DataTableProps<T> {
    46→  data: T[];
    47→  columns: Column<T>[];
    48→  actions?: TableAction<T>[];
    49→  onRowClick?: (row: T) => void;
    50→  className?: string;
    51→  mobileView?: "cards";
    52→  mobileCardConfig?: MobileCardConfig<T>;
    53→  pageSize?: number;
    54→  pageSizeOptions?: number[];
    55→}
    56→
    57→const ACTIONS_COLUMN_KEY = "__actions__";
    58→
    59→function buildActionsColumn<T>(actions: TableAction<T>[]): Column<T> {
    60→  return {
    61→    key: ACTIONS_COLUMN_KEY,
    62→    header: "Ações",
    63→    width: "1%",
    64→    className: "text-right",
    65→    render: (_: unknown, row: T): React.ReactNode => (
    66→      <div className="flex items-center justify-end gap-1">
    67→        {actions.map((action, i) => {
    68→          if (action.hidden?.(row)) return null;
    69→          return (
    70→            <Button
    71→              key={i}
    72→              variant="ghost"
    73→              size="icon"
    74→              onClick={(e: React.MouseEvent) => {
    75→                e.stopPropagation();
    76→                action.onClick(row, e);
    77→              }}
    78→              disabled={action.disabled?.(row)}
    79→              className={cn(
    80→                "h-8 w-8",
    81→                action.variant === "destructive" &&
    82→                  "text-red-600 hover:text-red-700 hover:bg-red-50"
    83→              )}
    84→              title={action.label}
    85→            >
    86→              {action.icon}
    87→            </Button>
    88→          );
    89→        })}
    90→      </div>
    91→    ),
    92→  };
    93→}
    94→
    95→export function DataTable<T extends object>({
    96→  data,
    97→  columns,
    98→  actions,
    99→  onRowClick,
   100→  className,
   101→  mobileView,
   102→  mobileCardConfig,
   103→  pageSize: initialPageSize,
   104→  pageSizeOptions,
   105→}: DataTableProps<T>): React.ReactElement {
   106→  const safeData = data || [];
   107→  const [pageIndex, setPageIndex] = useState(0);
   108→  const [pageSize, setPageSize] = useState(initialPageSize ?? 10);
   109→
   110→  const allColumns: Column<T>[] = actions?.length
   111→    ? [...columns, buildActionsColumn(actions)]
   112→    : columns;
   113→
   114→  const tanstackColumns: ColumnDef<T>[] = allColumns.map((col) => ({
   115→    id: String(col.key),
   116→    accessorFn: (row: T): unknown =>
   117→      (row as Record<string, unknown>)[String(col.key)],
   118→    header: () => col.header,
   119→    cell: ({ getValue, row }) =>
   120→      col.render
   121→        ? col.render(getValue(), row.original)
   122→        : String(getValue() ?? "-"),
   123→  }));
   124→
   125→  const table = useReactTable({
   126→    data: safeData,
   127→    columns: tanstackColumns,
   128→    getCoreRowModel: getCoreRowModel(),
   129→    ...(initialPageSize && {
   130→      getPaginationRowModel: getPaginationRowModel(),
   131→      state: { pagination: { pageIndex, pageSize } },
   132→      onPaginationChange: (updater) => {
   133→        const next =
   134→          typeof updater === "function"
   135→            ? updater({ pageIndex, pageSize })
   136→            : updater;
   137→        setPageIndex(next.pageIndex);
   138→        setPageSize(next.pageSize);
   139→      },
   140→    }),
   141→  });
   142→
   143→  const getMobileValue = (
   144→    row: T,
   145→    field: keyof T | ((row: T) => React.ReactNode) | undefined
   146→  ): React.ReactNode => {
   147→    if (!field) return null;
   148→    if (typeof field === "function") return field(row);
   149→    return String(row[field] || "-");
   150→  };
   151→
   152→  const actionsColForMobile = allColumns.find(
   153→    (col) => typeof col.header === "string" && col.header === "Ações"
   154→  );
   155→
   156→  return (
   157→    <div className={cn("w-full", className)}>
   158→      {/* Card View para Mobile */}
   159→      {mobileView === "cards" && (
   160→        <div className="grid grid-cols-1 gap-4 md:hidden mb-6">
   161→          {safeData.map((row, index) => (
   162→            <div
   163→              key={index}
   164→              onClick={() => onRowClick?.(row)}
   165→              className={cn(
   166→                "salon-card p-4 space-y-3",
   167→                onRowClick && "cursor-pointer active:bg-muted/50"
   168→              )}
   169→            >
   170→              <div className="flex justify-between items-start">
   171→                <div>
   172→                  <h4 className="font-medium text-primary text-[15px] leading-tight">
   173→                    {mobileCardConfig?.title
   174→                      ? getMobileValue(row, mobileCardConfig.title)
   175→                      : "Registro"}
   176→                  </h4>
   177→                  {mobileCardConfig?.subtitle && (
   178→                    <p className="text-[13px] text-muted-foreground mt-0.5">
   179→                      {getMobileValue(row, mobileCardConfig.subtitle)}
   180→                    </p>
   181→                  )}
   182→                </div>
   183→                {mobileCardConfig?.badge && (
   184→                  <span className="bg-secondary text-primary text-[10px] font-bold uppercase px-2 py-0.5 rounded-full">
   185→                    {getMobileValue(row, mobileCardConfig.badge)}
   186→                  </span>
   187→                )}
   188→              </div>
   189→
   190→              <div className="grid grid-cols-2 gap-3 pt-3 border-t-[0.5px] border-border/50">
   191→                {allColumns
   192→                  .filter(
   193→                    (col) =>
   194→                      typeof col.header === "string" &&
   195→                      col.header !== "Ações" &&
   196→                      col.header !== "Status" &&
   197→                      col.key !== mobileCardConfig?.title &&
   198→                      col.key !== mobileCardConfig?.subtitle &&
   199→                      col.key !== mobileCardConfig?.badge &&
   200→                      !mobileCardConfig?.excludeFromGrid?.includes(
   201→                        col.key as keyof T
   202→                      )
   203→                  )
   204→                  .slice(0, 6)
   205→                  .map((col) => (
   206→                    <div key={String(col.key)}>
   207→                      <p className="text-[10px] text-muted-foreground uppercase font-medium tracking-[0.06em]">
   208→                        {typeof col.header === "string" ? col.header : ""}
   209→                      </p>
   210→                      <p className="text-[13px] text-foreground font-normal truncate mt-0.5">
   211→                        {col.render
   212→                          ? col.render(
   213→                              (row as Record<string, unknown>)[String(col.key)],
   214→                              row
   215→                            )
   216→                          : String(
   217→                              (row as Record<string, unknown>)[
   218→                                String(col.key)
   219→                              ] || "-"
   220→                            )}
   221→                      </p>
   222→                    </div>
   223→                  ))}
   224→              </div>
   225→
   226→              {actionsColForMobile && (
   227→                <div className="pt-2 flex justify-end">
   228→                  {actionsColForMobile.render?.(null, row)}
   229→                </div>
   230→              )}
   231→            </div>
   232→          ))}
   233→          {safeData.length === 0 && (
   234→            <div className="salon-card p-8 text-center text-muted-foreground">
   235→              Nenhum registro encontrado
   236→            </div>
   237→          )}
   238→        </div>
   239→      )}
   240→
   241→      {/* Tabela Desktop */}
   242→      <div
   243→        className={cn(
   244→          "salon-card overflow-x-auto w-full rounded-lg",
   245→          mobileView === "cards" && "hidden md:block"
   246→        )}
   247→      >
   248→        <Table className="min-w-[600px]">
   249→          <TableHeader>
   250→            <TableRow className="salon-table-header hover:bg-tertiary">
   251→              {table.getFlatHeaders().map((header, index) => {
   252→                const col = allColumns.find(
   253→                  (c) => String(c.key) === header.id
   254→                );
   255→                return (
   256→                  <TableHead
   257→                    key={header.id}
   258→                    className={cn(
   259→                      "text-[13px] font-bold text-foreground whitespace-nowrap",
   260→                      col?.key !== ACTIONS_COLUMN_KEY && "pl-4",
   261→                      col?.className
   262→                    )}
   263→                    style={{ width: col?.width }}
   264→                  >
   265→                    {flexRender(
   266→                      header.column.columnDef.header,
   267→                      header.getContext()
   268→                    )}
   269→                  </TableHead>
   270→                );
   271→              })}
   272→            </TableRow>
   273→          </TableHeader>
   274→          <TableBody>
   275→            {table.getRowModel().rows.length === 0 ? (
   276→              <TableRow>
   277→                <TableCell
   278→                  colSpan={allColumns.length}
   279→                  className="text-center text-muted-foreground py-8"
   280→                >
   281→                  Nenhum registro encontrado
   282→                </TableCell>
   283→              </TableRow>
   284→            ) : (
   285→              table.getRowModel().rows.map((row) => (
   286→                <TableRow
   287→                  key={row.id}
   288→                  onClick={() => onRowClick?.(row.original)}
   289→                  className={cn(
   290→                    "border-border h-16 transition-colors",
   291→                    onRowClick && "cursor-pointer hover:bg-muted/30"
   292→                  )}
   293→                >
   294→                  {row.getVisibleCells().map((cell, cellIndex) => {
   295→                    const col = allColumns.find(
   296→                      (c) => String(c.key) === cell.column.id
   297→                    );
   298→                    return (
   299→                      <TableCell
   300→                        key={cell.id}
   301→                        className={cn(
   302→                          "text-[13px] align-middle py-4 px-4 whitespace-nowrap",
   303→                          col?.key !== ACTIONS_COLUMN_KEY && "pl-4",
   304→                          col?.className
   305→                        )}
   306→                        style={{ width: col?.width }}
   307→                      >
   308→                        {flexRender(
   309→                          cell.column.columnDef.cell,
   310→                          cell.getContext()
   311→                        )}
   312→                      </TableCell>
   313→                    );
   314→                  })}
   315→                </TableRow>
   316→              ))
   317→            )}
   318→          </TableBody>
   319→        </Table>
   320→      </div>
   321→
   322→      {/* Paginação */}
   323→      {initialPageSize && table.getPageCount() >= 1 && (
   324→        <ResponsivePagination
   325→          currentPage={pageIndex + 1}
   326→          totalPages={table.getPageCount()}
