import React, { useState } from "react";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  getPaginationRowModel,
  useReactTable,
} from "@tanstack/react-table";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { ResponsivePagination } from "@/components/ui/responsive-pagination";
import { cn } from "@/lib/utils";

export interface Column<T> {
  key: keyof T | string;
  header: React.ReactNode | string;
  render?: (value: any, row: T) => React.ReactNode;
  className?: string;
  width?: string;
}

export interface TableAction<T> {
  label: string;
  icon: React.ReactNode;
  onClick: (row: T, event: React.MouseEvent) => void;
  variant?: "default" | "destructive" | "outline" | "ghost";
  disabled?: (row: T) => boolean;
  hidden?: (row: T) => boolean;
}

interface MobileCardConfig<T> {
  title: keyof T | ((row: T) => React.ReactNode);
  subtitle?: keyof T | ((row: T) => React.ReactNode);
  badge?: keyof T | ((row: T) => React.ReactNode);
  excludeFromGrid?: (keyof T)[];
}

interface DataTableProps<T> {
  data: T[];
  columns: Column<T>[];
  actions?: TableAction<T>[];
  onRowClick?: (row: T) => void;
  className?: string;
  mobileView?: "cards";
  mobileCardConfig?: MobileCardConfig<T>;
  pageSize?: number;
  pageSizeOptions?: number[];
}

const ACTIONS_COLUMN_KEY = "__actions__";

function buildActionsColumn<T>(actions: TableAction<T>[]): Column<T> {
  return {
    key: ACTIONS_COLUMN_KEY,
    header: "Ações",
    width: "1%",
    className: "text-right",
    render: (_: unknown, row: T): React.ReactNode => (
      <div className="flex items-center justify-end gap-1">
        {actions.map((action, i) => {
          if (action.hidden?.(row)) return null;
          return (
            <Button
              key={i}
              variant="ghost"
              size="icon"
              onClick={(e: React.MouseEvent) => {
                e.stopPropagation();
                action.onClick(row, e);
              }}
              disabled={action.disabled?.(row)}
              className={cn(
                "h-8 w-8",
                action.variant === "destructive" &&
                  "text-red-600 hover:text-red-700 hover:bg-red-50"
              )}
              title={action.label}
            >
              {action.icon}
            </Button>
          );
        })}
      </div>
    ),
  };
}

export function DataTable<T extends object>({
  data,
  columns,
  actions,
  onRowClick,
  className,
  mobileView,
  mobileCardConfig,
  pageSize: initialPageSize,
  pageSizeOptions,
}: DataTableProps<T>): React.ReactElement {
  const safeData = data || [];
  const [pageIndex, setPageIndex] = useState(0);
  const [pageSize, setPageSize] = useState(initialPageSize ?? 10);

  const allColumns: Column<T>[] = actions?.length
    ? [...columns, buildActionsColumn(actions)]
    : columns;

  const tanstackColumns: ColumnDef<T>[] = allColumns.map((col) => ({
    id: String(col.key),
    accessorFn: (row: T): unknown =>
      (row as Record<string, unknown>)[String(col.key)],
    header: () => col.header,
    cell: ({ getValue, row }) =>
      col.render
        ? col.render(getValue(), row.original)
        : String(getValue() ?? "-"),
  }));

  const table = useReactTable({
    data: safeData,
    columns: tanstackColumns,
    getCoreRowModel: getCoreRowModel(),
    ...(initialPageSize && {
      getPaginationRowModel: getPaginationRowModel(),
      state: { pagination: { pageIndex, pageSize } },
      onPaginationChange: (updater) => {
        const next =
          typeof updater === "function"
            ? updater({ pageIndex, pageSize })
            : updater;
        setPageIndex(next.pageIndex);
        setPageSize(next.pageSize);
      },
    }),
  });

  const getMobileValue = (
    row: T,
    field: keyof T | ((row: T) => React.ReactNode) | undefined
  ): React.ReactNode => {
    if (!field) return null;
    if (typeof field === "function") return field(row);
    return String(row[field] || "-");
  };

  const actionsColForMobile = allColumns.find(
    (col) => typeof col.header === "string" && col.header === "Ações"
  );

  return (
    <div className={cn("w-full", className)}>
      {/* Card View para Mobile */}
      {mobileView === "cards" && (
        <div className="grid grid-cols-1 gap-4 md:hidden mb-6">
          {safeData.map((row, index) => (
            <div
              key={index}
              onClick={() => onRowClick?.(row)}
              className={cn(
                "salon-card p-4 space-y-3",
                onRowClick && "cursor-pointer active:bg-muted/50"
              )}
            >
              <div className="flex justify-between items-start">
                <div>
                  <h4 className="font-medium text-primary text-[15px] leading-tight">
                    {mobileCardConfig?.title
                      ? getMobileValue(row, mobileCardConfig.title)
                      : "Registro"}
                  </h4>
                  {mobileCardConfig?.subtitle && (
                    <p className="text-[13px] text-muted-foreground mt-0.5">
                      {getMobileValue(row, mobileCardConfig.subtitle)}
                    </p>
                  )}
                </div>
                {mobileCardConfig?.badge && (
                  <span className="bg-secondary text-primary text-[10px] font-bold uppercase px-2 py-0.5 rounded-full">
                    {getMobileValue(row, mobileCardConfig.badge)}
                  </span>
                )}
              </div>

              <div className="grid grid-cols-2 gap-3 pt-3 border-t-[0.5px] border-border/50">
                {allColumns
                  .filter(
                    (col) =>
                      typeof col.header === "string" &&
                      col.header !== "Ações" &&
                      col.header !== "Status" &&
                      col.key !== mobileCardConfig?.title &&
                      col.key !== mobileCardConfig?.subtitle &&
                      col.key !== mobileCardConfig?.badge &&
                      !mobileCardConfig?.excludeFromGrid?.includes(
                        col.key as keyof T
                      )
                  )
                  .slice(0, 6)
                  .map((col) => (
                    <div key={String(col.key)}>
                      <p className="text-[10px] text-muted-foreground uppercase font-medium tracking-[0.06em]">
                        {typeof col.header === "string" ? col.header : ""}
                      </p>
                      <p className="text-[13px] text-foreground font-normal truncate mt-0.5">
                        {col.render
                          ? col.render(
                              (row as Record<string, unknown>)[String(col.key)],
                              row
                            )
                          : String(
                              (row as Record<string, unknown>)[
                                String(col.key)
                              ] || "-"
                            )}
                      </p>
                    </div>
                  ))}
              </div>

              {actionsColForMobile && (
                <div className="pt-2 flex justify-end">
                  {actionsColForMobile.render?.(null, row)}
                </div>
              )}
            </div>
          ))}
          {safeData.length === 0 && (
            <div className="salon-card p-8 text-center text-muted-foreground">
              Nenhum registro encontrado
            </div>
          )}
        </div>
      )}

      {/* Tabela Desktop */}
      <div
        className={cn(
          "salon-card overflow-x-auto w-full rounded-lg",
          mobileView === "cards" && "hidden md:block"
        )}
      >
        <Table className="min-w-[600px]">
          <TableHeader>
            <TableRow className="salon-table-header hover:bg-tertiary">
              {table.getFlatHeaders().map((header, index) => {
                const col = allColumns.find(
                  (c) => String(c.key) === header.id
                );
                return (
                  <TableHead
                    key={header.id}
                    className={cn(
                      "text-[13px] font-bold text-foreground whitespace-nowrap",
                      col?.key !== ACTIONS_COLUMN_KEY && "pl-4",
                      col?.className
                    )}
                    style={{ width: col?.width }}
                  >
                    {flexRender(
                      header.column.columnDef.header,
                      header.getContext()
                    )}
                  </TableHead>
                );
              })}
            </TableRow>
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows.length === 0 ? (
              <TableRow>
                <TableCell
                  colSpan={allColumns.length}
                  className="text-center text-muted-foreground py-8"
                >
                  Nenhum registro encontrado
                </TableCell>
              </TableRow>
            ) : (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  onClick={() => onRowClick?.(row.original)}
                  className={cn(
                    "border-border h-16 transition-colors",
                    onRowClick && "cursor-pointer hover:bg-muted/30"
                  )}
                >
                  {row.getVisibleCells().map((cell, cellIndex) => {
                    const col = allColumns.find(
                      (c) => String(c.key) === cell.column.id
                    );
                    return (
                      <TableCell
                        key={cell.id}
                        className={cn(
                          "text-[13px] align-middle py-4 px-4 whitespace-nowrap",
                          col?.key !== ACTIONS_COLUMN_KEY && "pl-4",
                          col?.className
                        )}
                        style={{ width: col?.width }}
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext()
                        )}
                      </TableCell>
                    );
                  })}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      {/* Paginação */}
      {initialPageSize && table.getPageCount() >= 1 && (
        <ResponsivePagination
          currentPage={pageIndex + 1}
          totalPages={table.getPageCount()}
          totalItems={safeData.length}
          pageSize={pageSize}
          onPageChange={(page) => table.setPageIndex(page - 1)}
          onPageSizeChange={(size) => {
            setPageSize(Number(size));
            setPageIndex(0);
          }}
          pageSizeOptions={pageSizeOptions}
        />
      )}
    </div>
  );
}
